package code;

public class 연산자_비교연산자 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		// 연사의 결과가 true, false
		int su1=10;
		int su2=5;
		
		System.out.println(su1>su2);
		System.out.println(su1<su2);
		System.out.println(su1==su2);
		System.out.println(su1!=su2);
		System.out.println(su1<=su2);
		System.out.println(su1>=su2);

		boolean result = su1>su2;
		System.out.println(result);
	}

}
